import {cn} from '@/lib/utils';

/**
 * Renders a keyboard key or shortcut indicator styled as an inline badge.
 *
 * ### Component Props
 *
 * Accepts all standard `<kbd>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <Kbd>⌘</Kbd>
 * <Kbd>Shift</Kbd>
 * ```
 */
function Kbd({className, ...props}: React.ComponentProps<'kbd'>) {
  return (
    <kbd
      data-slot="kbd"
      className={cn(
        "pointer-events-none inline-flex h-5 w-fit min-w-5 items-center justify-center gap-1 rounded bg-muted px-1 font-sans text-xs font-label text-muted-foreground select-none in-data-[slot=tooltip-content]:bg-tooltip-kbd-bg in-data-[slot=tooltip-content]:text-background high-contrast:text-foreground [&_svg:not([class*='size-'])]:size-3",
        className
      )}
      {...props}
    />
  );
}

/**
 * Groups multiple `Kbd` elements together in an inline container.
 *
 * ### Component Props
 *
 * Accepts all standard `<div>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <KbdGroup>
 *   <Kbd>⌘</Kbd>
 *   <Kbd>K</Kbd>
 * </KbdGroup>
 * ```
 */
function KbdGroup({className, ...props}: React.ComponentProps<'div'>) {
  return (
    <kbd
      data-slot="kbd-group"
      className={cn('inline-flex items-center gap-1', className)}
      {...props}
    />
  );
}

export {Kbd, KbdGroup};
